Drop Table TRCD96A;
Drop Table TRED96A;
Drop Table TRMD96A;
Drop Table TRSD96A;
Drop Table TRCDLIST;
Drop Table TREDLIST;
Drop Table TRSDLIST;

Create Table TRCD96A
	(TAG Char (4) NOT NULL,
	NAME Varchar (254) NOT NULL,
	DESC Varchar (254),
	PRIMARY KEY (TAG));

Create Unique Index IDX_TRCD96A ON TRCD96A (TAG);

CREATE PUBLIC SYNONYM TRCD96A FOR SYSADM.TRCD96A;


Create Table TRED96A
	(TAG Char (4) NOT NULL,
	NAME Varchar (254) NOT NULL,
	DESC Varchar (254),
	REPR Char (7),
	PRIMARY KEY (TAG));

Create Unique Index IDX_TRED96A ON TRED96A (TAG);

CREATE PUBLIC SYNONYM TRED96A FOR SYSADM.TRED96A;


Create Table TRMD96A
	(TAG Char (6) NOT NULL,
	NAME Varchar (254) NOT NULL,
	VER Int,
	REL Int,
	ACTIVE Char (1),
	PRIMARY KEY (TAG));

Create Unique Index IDX_TRMD96A ON TRMD96A (TAG);

CREATE PUBLIC SYNONYM TRMD96A FOR SYSADM.TRMD96A;


Create Table TRSD96A
	(TAG Char (3) NOT NULL,
	NAME Varchar (254) NOT NULL,
	DESC Varchar (254),
	PRIMARY KEY (TAG));

Create Unique Index IDX_TRSD96A ON TRSD96A (TAG);

CREATE PUBLIC SYNONYM TRSD96A FOR SYSADM.TRSD96A;


Create Table TRCDLIST
	(TAG Char (4) NOT NULL,
	SEQ Int NOT NULL,
	TREDTAG Char (4),
	TREDDESC Varchar (254),
	STATUS Char(1),
	FOREIGN KEY TRCD (TAG) REFERENCES TRCD96A);

CREATE PUBLIC SYNONYM TRCDLIST FOR SYSADM.TRCDLIST;


Create Table TREDLIST
	(TAG Char (4) NOT NULL,
	VALUE Varchar (10) NOT NULL,
	NAME Varchar (254),
	DESC Varchar (254),
	FOREIGN KEY TRED (TAG) REFERENCES TRED96A);

CREATE PUBLIC SYNONYM TREDLIST FOR SYSADM.TREDLIST;


Create Table TRSDLIST
	(TAG Char (3) NOT NULL,
	SEQ Int NOT NULL,
	TRCDTAG Char (4),
	TRCDDESC Varchar (254),
	STATUS Char(1),
	FOREIGN KEY TRSD (TAG) REFERENCES TRSD96A);

CREATE PUBLIC SYNONYM TRSDLIST FOR SYSADM.TRSDLIST;

